import{_ as e,C as r,o as A,c as o,a5 as t,b as n,w as l,a as i,E as B,a4 as s}from"./chunks/framework.sOZL8giL.js";const S=JSON.parse('{"title":"开发、评估与安全","description":"","frontmatter":{},"headers":[],"relativePath":"05-Skill工程/03-开发与安全.md","filePath":"05-Skill工程/03-开发与安全.md","lastUpdated":null}'),p={name:"05-Skill工程/03-开发与安全.md"};function d(_,E,g,k,h,u){const a=r("Mermaid");return A(),o("div",null,[E[1]||(E[1]=t('<h1 id="开发、评估与安全" tabindex="-1">开发、评估与安全 <a class="header-anchor" href="#开发、评估与安全" aria-label="Permalink to &quot;开发、评估与安全&quot;">​</a></h1><blockquote><p>本章是 <strong>Hermes Engineering 系列</strong>第 5 模块的第 3 章。</p></blockquote><p>Skill 的完整实践指南——四条开发原则、安全考量、以及未来演进方向。</p><hr><h2 id="开发四原则" tabindex="-1">开发四原则 <a class="header-anchor" href="#开发四原则" aria-label="Permalink to &quot;开发四原则&quot;">​</a></h2><p><strong>最小化</strong>：一个 Skill 只解决一个领域的问题。Skill 的 <code>.md</code> 文件超过 2000 字考虑拆分。描述中出现&quot;同时&quot;&quot;另外&quot;&quot;顺便&quot;可能需要拆分。</p><p><strong>可发现性</strong>：用 Agent 能理解的语言写标题和描述，避免内部缩写。好的描述：&quot;部署代码到预发布环境，执行冒烟测试，等待人工确认后上线&quot;。</p><p><strong>可验证</strong>：每个 Skill 应有明确的成功标准——部署后检查服务健康、测试后检查报告、迁移后检查数据一致性。Agent 执行完 Skill 后能自我验证。</p><p><strong>可演进</strong>：版本化管理，更新时记录变更日志。新版本不破坏已有 Agent 行为。</p><hr><h2 id="安全考量" tabindex="-1">安全考量 <a class="header-anchor" href="#安全考量" aria-label="Permalink to &quot;安全考量&quot;">​</a></h2>',11)),(A(),n(s,null,{default:l(()=>[B(a,{id:"mermaid-31",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20A%5BSkill%20%E5%AE%89%E5%85%A8%E9%A3%8E%E9%99%A9%5D%20--%3E%20B%5BSkill%20%E6%B3%A8%E5%85%A5%3Cbr%2F%3E%E6%81%B6%E6%84%8F%E6%8C%87%E4%BB%A4%E8%A6%86%E7%9B%96%E7%B3%BB%E7%BB%9F%E7%BA%A6%E6%9D%9F%5D%0A%20%20%20%20A%20--%3E%20C%5B%E6%9D%A5%E6%BA%90%E9%A3%8E%E9%99%A9%3Cbr%2F%3E%E7%A4%BE%E5%8C%BA%20Skill%20%E5%90%AB%E6%81%B6%E6%84%8F%E5%86%85%E5%AE%B9%5D%0A%20%20%20%20A%20--%3E%20D%5B%E6%9D%83%E9%99%90%E8%B6%8A%E7%95%8C%3Cbr%2F%3ESkill%20%E8%AE%BF%E9%97%AE%E4%B8%8D%E8%AF%A5%E7%A2%B0%E7%9A%84%E8%B5%84%E6%BA%90%5D%0A%20%20%20%20B%20--%3E%20E%5B%E7%BC%93%E8%A7%A3%3A%20%E6%B2%99%E7%AE%B1%E6%89%A7%E8%A1%8C%3Cbr%2F%3E%E5%AE%A1%E6%9F%A5%E5%86%85%E5%AE%B9%2B%E6%A0%87%E8%AE%B0%E9%9A%94%E7%A6%BB%5D%0A%20%20%20%20C%20--%3E%20F%5B%E7%BC%93%E8%A7%A3%3A%20%E7%AD%BE%E5%90%8D%E9%AA%8C%E8%AF%81%3Cbr%2F%3E%E5%8F%AA%E5%8A%A0%E8%BD%BD%E5%8F%AF%E4%BF%A1%E6%9D%A5%E6%BA%90%5D%0A%20%20%20%20D%20--%3E%20G%5B%E7%BC%93%E8%A7%A3%3A%20L1-L4%20%E6%9D%83%E9%99%90%E5%88%86%E7%BA%A7%5D%0A%20%20%20%20G%20--%3E%20H%5BL1%20%E5%8F%AA%E8%AF%BB%E6%9F%A5%E8%AF%A2%5D%0A%20%20%20%20G%20--%3E%20I%5BL2%20%E6%9C%89%E9%99%90%E5%86%99%E6%96%87%E4%BB%B6%5D%0A%20%20%20%20G%20--%3E%20J%5BL3%20%E5%A4%96%E9%83%A8%E8%AE%BF%E9%97%AEAPI%5D%0A%20%20%20%20G%20--%3E%20K%5BL4%20%E7%89%B9%E6%9D%83%E6%93%8D%E4%BD%9C%E9%83%A8%E7%BD%B2%5D%0A%20%20%20%20H%20--%3E%20L%5B%E6%AF%8F%E4%B8%AASkill%E5%8F%AA%E8%AE%BF%E9%97%AE%3Cbr%2F%3E%E5%AE%83%E7%9C%9F%E6%AD%A3%E9%9C%80%E8%A6%81%E7%9A%84%E8%B5%84%E6%BA%90%5D%0A%20%20%20%20I%20--%3E%20L%0A%20%20%20%20J%20--%3E%20L%0A%20%20%20%20K%20--%3E%20L%0A"})]),fallback:l(()=>[...E[0]||(E[0]=[i(" Loading... ",-1)])]),_:1})),E[2]||(E[2]=t('<blockquote><p>💡 <strong>图解：</strong> 安全不是锦上添花——一个恶意 Skill 可能让整个 Agent 系统沦为攻击工具，权限分级是最后的防线。</p></blockquote><p><strong>Skill 注入风险</strong>：恶意 Skill 可能在指令中包含 Prompt Injection。缓解——沙箱执行、审查内容移除系统标记、明确告诉 Agent Skill 指令不能覆盖系统级约束。</p><p><strong>权限分级</strong>：L1 只读（查询类）、L2 有限写（文件操作）、L3 外部访问（API 调用）、L4 特权操作（部署删除）。每个 Skill 只能访问它真正需要的资源。</p><p><strong>来源验证</strong>：社区分享的 Skill 可能包含恶意内容。使用签名机制验证来源，只加载可信或经过审查的 Skill。</p><hr><h2 id="评估与未来" tabindex="-1">评估与未来 <a class="header-anchor" href="#评估与未来" aria-label="Permalink to &quot;评估与未来&quot;">​</a></h2><p><strong>自动化测试</strong>：像测试代码一样测试 Skill——功能正确性、鲁棒性、Token 效率。A/B 测试新旧版本效果。</p><p><strong>未来演进</strong>：Skill 市场（类似 npm 的注册中心）、自动 Skill 生成（从用户行为模式学习）、跨 Agent 复用（标准化接口）。</p><hr><h2 id="本章要点" tabindex="-1">本章要点 <a class="header-anchor" href="#本章要点" aria-label="Permalink to &quot;本章要点&quot;">​</a></h2><ul><li>开发四原则：最小化、可发现性、可验证、可演进</li><li>安全：注入风险、权限分级（L1-L4）、来源验证</li><li>评估：自动化测试、A/B 测试</li><li>未来：Skill 市场、自动生成、跨 Agent 复用</li></ul><hr><p><strong>上一章</strong>: <a href="./02-渐进式披露.html">渐进式披露</a></p><hr><p><a href="/">← 返回首页</a> | <a href="/06-Agent评估/">下一模块: Agent评估 →</a></p>',15))])}const c=e(p,[["render",d]]);export{S as __pageData,c as default};
